const body = $input.first().json.body || $input.first().json;
const userMessage = body.message ?? body.user_message ?? body.text ?? '';
if (!userMessage) {
  return [{ json: { error: 'Missing message, user_message, or text in request body.', _skipGovernor: true } }];
}
return [{
  json: {
    user_message: userMessage,
    context: {
      domain: 'animal_diet_feedouts',
      scope: 'Employee questions about diet feedouts for animals. Answers must be factual, constrained to feed schedules, rations, and verified data. No persuasion or moralizing.'
    }
  }
}];

const item = $input.first().json;
if (item._skipGovernor) {
  return [{ json: { success: false, error: item.error, answer: null, next_actions: [], options: [] } }];
}
if (item.error) {
  return [{ json: { success: false, error: item.error, answer: null, next_actions: [], options: [] } }];
}
if (item.code && item.message) {
  return [{ json: { success: false, error: 'Governor service unavailable: ' + (item.message || item.code), answer: null, next_actions: [], options: [] } }];
}
const resolution = item.resolution || {};
const approval = item.approval || {};
return [{
  json: {
    success: approval.approved === true,
    answer: resolution.answer || null,
    next_actions: resolution.next_actions || [],
    options: resolution.options || [],
    approved: approval.approved,
    drift_score: (item.reflection || {}).drift_score,
    structure_score: approval.structure_score,
    _full: item
  }
}];
